<?php
require_once __DIR__ . '/includes/functions.php'; startSecureSession(); require_once __DIR__ . '/includes/db.php'; requireAccountant($pdo);
$uid = getLoggedInUserId();
if ($_SERVER['REQUEST_METHOD']==='POST'){ verifyCsrfOrFail(); $name=trim((string)($_POST['name']??'')); $city=trim((string)($_POST['city']??'')); $isDefault=isset($_POST['is_default'])?1:0; if($name!==''){ if($isDefault){ $pdo->exec('UPDATE societies SET is_default = 0'); } $pdo->prepare('INSERT INTO societies (name, city, is_default, active, created_at) VALUES (?, ?, ?, 1, NOW())')->execute([$name,$city,$isDefault]); systemLog($pdo,$uid,'society','create',$name); setFlash('success','Society saved.'); header('Location: death_societies.php'); exit; } }
$rows = getSocieties($pdo); require_once __DIR__ . '/includes/header.php';
?><h1 class="title">Death Insurance Societies</h1><div class="grid-2"><div class="card stack"><form method="post" class="stack"><?= csrfField() ?><div><label>Name</label><input type="text" name="name" required></div><div><label>City</label><input type="text" name="city"></div><div class="switch-row"><div><strong>Default Society</strong></div><label><input type="checkbox" name="is_default" value="1"> Default</label></div><button class="btn btn-primary" type="submit">Save Society</button></form></div><div class="card"><h2 style="margin-top:0">Society List</h2><?php foreach($rows as $row): ?><div class="meter-row"><div><strong><?= e((string)$row['name']) ?></strong><br><span class="muted"><?= e((string)$row['city']) ?></span></div><div><?php if((int)$row['is_default']===1): ?><span class="tag blue">Default</span><?php endif; ?></div></div><?php endforeach; ?></div></div><?php require_once __DIR__ . '/includes/footer.php'; ?>
